import React, { useState } from 'react';
import { Copy, CheckCircle } from 'lucide-react';

const InformativeWebsite = () => {
  const [copiedIndex, setCopiedIndex] = useState(null);

  const handleCopy = (text, index) => {
    navigator.clipboard.writeText(text).then(() => {
      setCopiedIndex(index);
      setTimeout(() => setCopiedIndex(null), 2000);
    });
  };

  return (
    <div className="bg-gray-900 text-white h-screen overflow-y-auto">
      <div className="max-w-4xl mx-auto space-y-8 py-12">
        {/* Intro Section */}
        <section>
          <h1 className="text-4xl font-bold mb-4">Basic information for pleadings.</h1>
          <p className="text-lg text-gray-300">
            Primer párrafo con información relevante sobre el tema principal del sitio web. Aquí se introduce el
            contexto y se captura la atención del lector. Se pueden incluir datos interesantes o estadísticas que
            generen interés. La información debe ser clara y concisa para mantener la atención.
          </p>
        </section>

        {/* Details Section */}
        <section>
          <h2 className="text-2xl font-bold mb-4">Detalles Adicionales</h2>
          <p className="text-lg text-gray-300">
            Segundo párrafo que profundiza en los detalles introducidos anteriormente. Se explican conceptos
            más específicos relacionados con el tema principal. Se pueden agregar ejemplos o casos de
            estudio que ilustren la información. El objetivo es proporcionar más contexto y comprensión al
            lector.
          </p>
        </section>

        {/* Copy Box Section */}
        <section>
          <div className="bg-gray-800 p-6 rounded-lg">
            <div className="flex items-center justify-between mb-4">
              <h3 className="text-xl font-semibold">Texto para Copiar</h3>
              <button 
                onClick={() => handleCopy('Tu texto aquí para copiar', 0)}
                className="text-gray-400 hover:text-blue-400"
              >
                {copiedIndex === 0 ? (
                  <CheckCircle className="w-6 h-6 text-green-500" />
                ) : (
                  <Copy className="w-6 h-6" />
                )}
              </button>
            </div>
            <pre className="bg-gray-900 p-4 rounded-md text-gray-300 overflow-x-auto">
              Tu texto aquí para copiar
            </pre>
          </div>
        </section>

        {/* Additional Info Section */}
        <section>
          <h2 className="text-2xl font-bold mb-4">Información Adicional</h2>
          <p className="text-lg text-gray-300">
            Tercer párrafo que continúa desarrollando el tema principal. Se pueden introducir nuevos aspectos
            o perspectivas relacionadas. La información debe ser coherente con los párrafos anteriores. Se
            busca mantener el interés del lector con contenido relevante.
          </p>
          <p className="text-lg text-gray-300 mt-4">
            Cuarto párrafo que concluye o resume los puntos principales. Se pueden incluir reflexiones o
            conclusiones importantes. Se destaca el valor o la relevancia de la información presentada. El
            objetivo es dejar un impacto final en el lector.
          </p>
        </section>

        {/* Image Section */}
        <section>
          <h2 className="text-2xl font-bold mb-4">Imagen Ilustrativa</h2>
          <img
            src="/api/placeholder/800/400"
            alt="Imagen Ilustrativa"
            className="w-full rounded-lg shadow-md"
          />
          <p className="text-sm text-gray-400 mt-2 text-center">
            Descripción o pie de foto para la imagen
          </p>
        </section>
      </div>
    </div>
  );
};

export default InformativeWebsite;
